from .detectors import _draw_settingfrom .molecules import _draw_moleculefrom .utils import *from criresviz.models import CRIRESSetting, Moleculeimport matplotlib.pyplot as pltdef _as_list(obj):    if obj is None:        return []    if isinstance(obj, (list, tuple)):        return obj    return [obj]def _classify(objects):    settings = []    molecules = []    for obj in _as_list(objects):        if isinstance(obj, CRIRESSetting):            settings.append(obj)        elif isinstance(obj, Molecule):            molecules.append(obj)        else:            raise TypeError(                f"Unsupported object type: {type(obj).__name__}"            )    return settings, moleculesdef plot(    *objects,    sky=None,    planet=None,    layout="wavelength",    ax=None,):    settings, molecules = _classify(objects)    settings = _as_list(settings)    molecules = _as_list(molecules)        settings = sorted(        settings,        key=lambda s: s.wavelength_range[0]    )        if layout == "compact":        fig, axes = make_compact_axes(settings)            for ax, setting in zip(axes, settings):            _draw_setting(setting, ax)                for molecule in molecules:                _draw_molecule(molecule, ax, clip=True)                                        style_compact_axes(axes, settings)        add_break_marks(axes)        fig.suptitle("CRIRES+ wavelength coverage", fontsize=14)        fig.supxlabel("Wavelength (μm)")                return axes        else:        ax = prepare_axes(ax)        for setting in settings:            _draw_setting(setting, ax)            for molecule in molecules:            _draw_molecule(molecule, ax, clip=False)                    ax.set_title("CRIRES+ wavelength coverage")        style_axes(ax)        ax.legend()           return ax